const HANSON_LOGO_BASE64 = "data:image/png;base64,";
// Hanson Intermediation Invoice Generator - app.js
// Encoding: UTF-8

document.addEventListener("DOMContentLoaded", () => {
    // Check if html2pdf is loaded
    if (typeof html2pdf === "undefined") {
        console.warn("AvÃ­s: La llibreria html2pdf no s'ha carregat correctament.");
    }
    // Currency Formatter
    const eur = new Intl.NumberFormat("ca-ES", {
        style: "currency",
        currency: "EUR"
    });

    // DOM Elements - Inputs
    const numFacturaInput = document.getElementById("num-factura");
    const dataFacturaInput = document.getElementById("data-factura");
    const tipusOperacioInput = document.getElementById("tipus-operacio");
    const nomClientInput = document.getElementById("nom-client");
    const nrtClientInput = document.getElementById("nrt-client");
    const adrecaClientInput = document.getElementById("adreca-client");
    const immobleReferenciaInput = document.getElementById("immoble-referencia");
    const importBaseInput = document.getElementById("import-base");
    const downloadPdfBtn = document.getElementById("download-pdf-btn");

    // Apply Base64 Logo (to prevent 'Tainted Canvas' error on local files)
    const displayLogo = document.getElementById("display-logo");
    if (displayLogo && typeof HANSON_LOGO_BASE64 !== "undefined") {
        displayLogo.src = HANSON_LOGO_BASE64;
    }

    // DOM Elements - Preview
    const displayNumFactura = document.getElementById("display-num-factura");
    // ... rest of the code ... (keeping current lines as is)
    const displayDataFactura = document.getElementById("display-data-factura");
    const displayNomClient = document.getElementById("display-nom-client");
    const displayNrtClient = document.getElementById("display-nrt-client");
    const displayNrtClientRow = document.getElementById("display-nrt-client-row");
    const displayAdrecaClient = document.getElementById("display-adreca-client");
    const displayReference = document.getElementById("display-reference");
    const displayMainDesc = document.getElementById("display-main-desc");
    const displayPropertySubdesc = document.getElementById("display-property-subdesc");
    const displayBaseAmount = document.getElementById("display-base-amount");
    const displayTotalBase = document.getElementById("display-total-base");
    const displayIgi = document.getElementById("display-igi");
    const displayGrandTotal = document.getElementById("display-grand-total");

    function updateInvoice() {
        // Metadata
        displayNumFactura.textContent = numFacturaInput.value;
        
        const dateValue = dataFacturaInput.value;
        if (dateValue) {
            const dateObj = new Date(dateValue);
            displayDataFactura.textContent = dateObj.toLocaleDateString("ca-ES");
        } else {
            displayDataFactura.textContent = "";
        }

        // Client Info
        displayNomClient.textContent = nomClientInput.value;
        
        const nrtValue = nrtClientInput.value.trim();
        if (nrtValue) {
            displayNrtClient.textContent = nrtValue;
            displayNrtClientRow.style.display = "block";
        } else {
            displayNrtClientRow.style.display = "none";
        }

        displayAdrecaClient.textContent = adrecaClientInput.value;

        // Reference / Property
        const refValue = immobleReferenciaInput.value;
        displayReference.textContent = refValue;
        displayPropertySubdesc.textContent = refValue;

        // Description
        const opType = tipusOperacioInput.value;
        if (opType === "Venda") {
            displayMainDesc.textContent = "Honoraris d'intermediaci\u00f3 en operaci\u00f3 de venda";
        } else {
            displayMainDesc.textContent = "Honoraris d'intermediaci\u00f3 en operaci\u00f3 de lloguer";
        }

        // Calculations
        const base = parseFloat(importBaseInput.value) || 0;
        const igi = base * 0.045;
        const total = base + igi;

        // Totals Display
        displayBaseAmount.textContent = eur.format(base);
        displayTotalBase.textContent = eur.format(base);
        displayIgi.textContent = eur.format(igi);
        displayGrandTotal.textContent = eur.format(total);
    }

    // Event Listeners
    const inputs = [
        numFacturaInput, 
        dataFacturaInput, 
        tipusOperacioInput, 
        nomClientInput, 
        nrtClientInput, 
        adrecaClientInput, 
        immobleReferenciaInput, 
        importBaseInput
    ];

    inputs.forEach(input => {
        input.addEventListener("input", updateInvoice);
        if (input.tagName === "SELECT") {
            input.addEventListener("change", updateInvoice);
        }
    });

    // PDF Generation
    downloadPdfBtn.addEventListener("click", () => {
        console.log("Generant PDF...");
        const element = document.getElementById("invoice-preview");
        const invoiceNum = numFacturaInput.value.replace(/\//g, '-') || 'proforma';
        
        // Configuration for html2pdf
        const opt = {
            margin:       0,
            filename:     `Factura_${invoiceNum}.pdf`,
            image:        { type: 'jpeg', quality: 0.98 },
            html2canvas:  { 
                scale: 1.5, // Slightly lower scale for stability
                useCORS: true, 
                backgroundColor: '#ffffff',
                scrollY: 0,
                windowWidth: 794, // Fixed width in pixels for standard A4 at 96dpi
                windowHeight: 1123 // Fixed height in pixels
            },
            jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' }
        };

        // Execution with better error capture
        try {
            html2pdf()
                .from(element)
                .set(opt)
                .save()
                .then(() => {
                    console.log("PDF generat correctament.");
                })
                .catch(err => {
                    console.error("Error en html2pdf:", err);
                    alert("Error detallat: " + (err.message || err.toString() || "Error desconegut"));
                });
        } catch (err) {
            console.error("Error d'execuci\u00f3:", err);
            alert("Error d'execuci\u00f3: " + err.message);
        }
    });

    // Initial call
    updateInvoice();
});

